search:
{% if posts %}
{% for post in posts.toArray() %}
  {% if not post.hide and (post.indexing == undefined or post.indexing) %}

    {{ post.title }}

    {{ (url + post.path) | uriencode }}
    {% if content %}
      {{ post.content | noControlChars | safe }}
    {% endif %}
    {% if post.categories and post.categories.length > 0 %}

        {% for cate in post.categories.toArray() %}
        {{ cate.name }}
        {% endfor %}

    {% endif %}
    {% if post.tags and post.tags.length > 0 %}

        {% for tag in post.tags.toArray() %}
        {{ tag.name }}
        {% endfor %}

    {% endif %}

  {% endif %}
{% endfor %}
{% endif %}
